return [{
  json: {
    // ---- 1. Sources ----------------------------------------------------------
    // Any RSS/Atom URL. One bad feed will not stop the others (RSS Read is set
    // to continueRegularOutput).
    feeds: [
      "https://www.theverge.com/rss/index.xml",
      "https://techcrunch.com/feed/",
      "https://www.reuters.com/business/finance/rss",
      "https://feeds.bbci.co.uk/news/business/rss.xml"
    ],

    // ---- 2. Topics -----------------------------------------------------------
    // Each topic has an include list (ALL terms must be present, boolean AND)
    // and an exclude list (any match → topic skipped). Whole-word, case-
    // insensitive. An article that matches NO topic is dropped.
    topics: [
      {
        name: "BrandMentions",
        include: ["acme"],
        exclude: ["acme tool company", "wile e coyote"]
      },
      {
        name: "Competitors",
        include: ["globex"],
        exclude: []
      },
      {
        name: "RegulatoryNews",
        include: ["regulation"],
        exclude: ["sports", "fashion"]
      }
    ],

    // ---- 3. Scoring ----------------------------------------------------------
    // Relevance score = clamp(0..100, round(
    //   termWeight   * min(totalIncludeHits, 10)
    // + sourceWeight * min(sources[host] || sources.default || 1, 2)
    // + recencyWeight * max(0, 1 - hoursOld / recencyHalfLifeHours)
    // ))
    scoring: {
      termWeight: 6,            // raise to ~12 if you want keyword density to dominate (good for very specific brand names)
      sourceWeight: 20,         // raise if you trust a few outlets a lot more than the rest
      recencyWeight: 30,        // lower to ~10 for slow-moving regulatory/industry feeds; raise for breaking-news monitoring
      recencyHalfLifeHours: 48, // raise to 168 (1 week) for weekly digests; lower to 12 for "what happened overnight"
      sources: {
        "reuters.com": 1.5,
        "bbc.co.uk":   1.4,
        "techcrunch.com": 1.2,
        "theverge.com": 1.1,
        default: 1.0           // anything not listed above gets this multiplier
      }
    },

    // ---- 4. Sentiment lexicon -----------------------------------------------
    // AFINN-style word → integer score (typical −5..+5). Sum is normalised by
    // sqrt(tokenCount) so long articles don't dominate. Label thresholds:
    //   ≥ +0.5 → positive,  ≤ -0.5 → negative,  else neutral.
    lexicon: {
      surge: 3, soar: 3, beat: 2, growth: 2, profit: 2, win: 2, gain: 2,
      record: 1, upbeat: 2, strong: 1, rise: 1, rally: 2,
      loss: -2, miss: -2, slump: -3, plunge: -3, fall: -1, drop: -1,
      lawsuit: -3, fraud: -4, breach: -3, scandal: -3, fine: -2, probe: -2,
      layoff: -3, layoffs: -3, recall: -2, hack: -3, outage: -2
    },

    // ---- 5. Entity dictionary -----------------------------------------------
    // Label → list of aliases. Whole-word, case-insensitive. Each label is
    // attached at most once per article.
    entities: {
      "Acme Corp":  ["acme", "acme corp", "acmecorp"],
      "Globex Inc": ["globex", "globex corp"],
      "Initech":    ["initech"]
    },

    // ---- 6. Digest email ----------------------------------------------------
    digest: {
      subjectPrefix: "[MediaMonitor]",
      minRelevance: 30,   // hide low-score noise from the email
      maxItems: 50,       // hard cap across all topics
      to: "ops@example.com",
      from: "monitor@example.com"
    },

    // ---- 7. Dedup --------------------------------------------------------
    // Max number of link hashes kept in workflow static data. Older entries
    // are dropped FIFO.
    seenCap: 5000
  }
}];

// ---- Starter-pack topics (uncomment and rename to use) ----------------------
// Drop any of these into topics[] above. Replace the placeholder terms with
// your real brand/competitor/regulator/industry keywords.
//
//   { name: "OwnBrand",        include: ["yourbrand"],         exclude: [] },
//   { name: "Top3Competitors", include: ["competitor"],        exclude: [] },
//   { name: "RegulatoryRisk",  include: ["regulator"],         exclude: ["sports"] },
//   { name: "IndustryGeneral", include: ["fintech"],           exclude: ["crypto"] },
//   { name: "Tourism",         include: ["tourism"],           exclude: [] },
//   { name: "Hospitality",     include: ["hotel"],             exclude: ["hotel california"] },
//   { name: "Cruise",          include: ["cruise"],            exclude: ["tom cruise", "cruise missile"] },

// Fan out: one item per feed URL from Config.
const feeds = $('Config').first().json.feeds || [];
return feeds.map(url => ({ json: { url } }));

// Process Articles — rule-based enrichment.
// Pure functions are inlined below (copy of src/lib.mjs) so this node is
// self-contained inside the exported workflow. Edit src/lib.mjs and re-run
// scripts/build-workflow.mjs to regenerate.

const HTML_ENTITIES = {
  '&amp;': '&', '&lt;': '<', '&gt;': '>',
  '&quot;': '"', '&#39;': "'", '&apos;': "'", '&nbsp;': ' '
};

function stripHtml(s) {
  if (!s) return '';
  return String(s)
    .replace(/<\s*br\s*\/?\s*>/gi, ' ')
    .replace(/<\/?\s*(p|div|li|h[1-6])\s*>/gi, ' ')
    .replace(/<[^>]+>/g, '')
    .replace(/&(amp|lt|gt|quot|#39|apos|nbsp);/g, m => HTML_ENTITIES[m] ?? m)
    .replace(/\s+/g, ' ')
    .trim();
}

function safeHostname(link) {
  try {
    return new URL(link).hostname.replace(/^www\./, '').toLowerCase();
  } catch {
    return '';
  }
}

function escapeRegex(s) {
  return String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function termRegex(term) {
  // Whole-word, case-insensitive. \b works for ASCII; phrases with spaces
  // get \b on the outer tokens which is the common-case intent.
  return new RegExp(`\\b${escapeRegex(term)}\\b`, 'gi');
}

function countMatches(haystack, term) {
  const m = haystack.match(termRegex(term));
  return m ? m.length : 0;
}

function hasMatch(haystack, term) {
  return termRegex(term).test(haystack);
}

/**
 * Cut a summary at `n` characters on a word boundary and append an ellipsis.
 * Used by the digest builder for tidy article previews.
 * @param {string} text  - input string
 * @param {number} [n=280] - max length before truncation
 * @returns {string} truncated text, or original if already short enough
 */
function truncateSummary(text, n = 280) {
  const s = String(text ?? '');
  if (s.length <= n) return s;
  const cut = s.slice(0, n);
  const lastSpace = cut.lastIndexOf(' ');
  return (lastSpace > n * 0.6 ? cut.slice(0, lastSpace) : cut) + '…';
}

/**
 * Normalise a raw RSS/Atom item into a flat article shape.
 * Strips HTML, picks the best content field, derives `source` from the link host,
 * and parses `publishedAt` to ISO 8601.
 * @param {object} raw - raw feed item (from n8n RSS Read node)
 * @param {string} feedUrl - the feed URL (fallback for source host)
 * @returns {{title:string, link:string, source:string, publishedAt:string, summary:string, contentText:string}}
 */
function normalizeArticle(raw, feedUrl) {
  const title = stripHtml(raw?.title ?? '');
  const link = String(raw?.link ?? raw?.url ?? raw?.guid ?? '').trim();
  const summary = stripHtml(raw?.contentSnippet ?? raw?.summary ?? raw?.description ?? '');
  const content = stripHtml(raw?.content ?? raw?.['content:encoded'] ?? '');
  const contentText = (content && content.length > summary.length) ? content : summary;
  const published = raw?.isoDate ?? raw?.pubDate ?? raw?.published ?? raw?.date ?? null;
  let publishedAt;
  if (published) {
    const d = new Date(published);
    publishedAt = isNaN(d.getTime()) ? new Date().toISOString() : d.toISOString();
  } else {
    publishedAt = new Date().toISOString();
  }
  const source = safeHostname(link) || safeHostname(feedUrl) || '';
  return { title, link, source, publishedAt, summary, contentText };
}

/**
 * Hash a URL to a short stable fingerprint for cross-run dedup.
 * Lowercases, strips tracking query params (utm_*, gclid, fbclid, mc_cid, mc_eid),
 * drops trailing slash and fragment, then djb2 → 32-bit hex.
 * @param {string} link
 * @returns {string} 8-char hex fingerprint, '0' for empty input
 */
function hashLink(link) {
  if (!link) return '0';
  let normalized = String(link).trim().toLowerCase();
  try {
    const u = new URL(normalized);
    u.hash = '';
    const drop = [];
    for (const k of u.searchParams.keys()) {
      if (k.startsWith('utm_') || k === 'gclid' || k === 'fbclid' || k === 'mc_cid' || k === 'mc_eid') {
        drop.push(k);
      }
    }
    drop.forEach(k => u.searchParams.delete(k));
    normalized = `${u.protocol}//${u.hostname}${u.pathname.replace(/\/$/, '')}${u.search}`;
  } catch {
    normalized = normalized.replace(/#.*$/, '').replace(/\/$/, '');
  }
  // djb2 32-bit
  let h = 5381;
  for (let i = 0; i < normalized.length; i++) {
    h = (((h << 5) + h) + normalized.charCodeAt(i)) | 0;
  }
  return (h >>> 0).toString(16);
}

/**
 * Whole-word, case-insensitive boolean topic match.
 * For each topic: ALL include[] terms must appear AND no exclude[] term may appear.
 * @param {{title?:string, contentText?:string}} article
 * @param {Array<{name:string, include:string[], exclude:string[]}>} topics
 * @returns {string[]} names of topics matched, [] if none
 */
function matchTopics(article, topics) {
  const hay = `${article.title ?? ''} ${article.contentText ?? ''}`;
  const matched = [];
  for (const t of topics ?? []) {
    const include = t.include ?? [];
    const exclude = t.exclude ?? [];
    if (include.length === 0) continue;
    const allInclude = include.every(term => hasMatch(hay, term));
    if (!allInclude) continue;
    const anyExclude = exclude.some(term => hasMatch(hay, term));
    if (anyExclude) continue;
    matched.push(t.name);
  }
  return matched;
}

/**
 * Compute a relevance score 0–100 from term frequency, source weight, recency.
 * @param {{title?:string, contentText?:string, source?:string, publishedAt?:string}} article
 * @param {string[]} topicsMatched - names of topics this article matched
 * @param {object} scoring - { termWeight, sourceWeight, recencyWeight, recencyHalfLifeHours, sources }
 * @param {Array<{name:string, include:string[]}>} allTopics
 * @param {number} [now=Date.now()] - reference timestamp for recency math
 * @returns {number} integer 0..100
 */
function scoreRelevance(article, topicsMatched, scoring, allTopics, now = Date.now()) {
  if (!topicsMatched || topicsMatched.length === 0) return 0;
  const cfg = scoring ?? {};
  const termWeight = cfg.termWeight ?? 6;
  const sourceWeight = cfg.sourceWeight ?? 20;
  const recencyWeight = cfg.recencyWeight ?? 30;
  const halfLife = cfg.recencyHalfLifeHours ?? 48;
  const sources = cfg.sources ?? {};

  const hay = `${article.title ?? ''} ${article.contentText ?? ''}`;
  let hits = 0;
  for (const tName of topicsMatched) {
    const t = (allTopics ?? []).find(x => x.name === tName);
    if (!t) continue;
    for (const term of t.include ?? []) {
      hits += countMatches(hay, term);
    }
  }
  // cap hits so a keyword-stuffed article doesn't dominate
  const cappedHits = Math.min(hits, 10);
  const termComponent = cappedHits * termWeight;

  const srcMultiplier = sources[article.source] ?? sources.default ?? 1;
  const sourceComponent = sourceWeight * Math.min(srcMultiplier, 2); // clamp absurd weights

  const published = new Date(article.publishedAt ?? now).getTime();
  const hoursOld = Math.max(0, (now - published) / 36e5);
  const recencyComponent = recencyWeight * Math.max(0, 1 - hoursOld / halfLife);

  const total = termComponent + sourceComponent + recencyComponent;
  return Math.max(0, Math.min(100, Math.round(total)));
}

/**
 * AFINN-style sentiment. Sum lexicon[word] across whole-word tokens, normalise
 * by sqrt(tokenCount) so long articles don't dominate.
 * @param {{title?:string, contentText?:string}} article
 * @param {Record<string, number>} lexicon - word → integer (typical −5..+5)
 * @returns {{score:number, label:'positive'|'neutral'|'negative'}}
 */
function scoreSentiment(article, lexicon) {
  const text = `${article.title ?? ''} ${article.contentText ?? ''}`.toLowerCase();
  const tokens = text.match(/[a-z][a-z'-]+/g) ?? [];
  if (tokens.length === 0) return { score: 0, label: 'neutral' };
  let raw = 0;
  for (const tok of tokens) {
    const v = lexicon?.[tok];
    if (typeof v === 'number') raw += v;
  }
  const score = raw / Math.sqrt(tokens.length);
  const rounded = Math.round(score * 100) / 100;
  let label = 'neutral';
  if (rounded >= 0.5) label = 'positive';
  else if (rounded <= -0.5) label = 'negative';
  return { score: rounded, label };
}

/**
 * Tag entities by alias. Each label is attached at most once per article.
 * @param {{title?:string, contentText?:string}} article
 * @param {Record<string, string[]>} entities - label → aliases (whole-word, case-insensitive)
 * @returns {string[]} unique labels matched
 */
function tagEntities(article, entities) {
  const hay = `${article.title ?? ''} ${article.contentText ?? ''}`;
  const found = new Set();
  for (const [label, aliases] of Object.entries(entities ?? {})) {
    for (const alias of aliases ?? []) {
      if (hasMatch(hay, alias)) { found.add(label); break; }
    }
  }
  return [...found];
}


const cfg = $('Config').first().json;
const store = $getWorkflowStaticData('global');
if (!Array.isArray(store.seen)) store.seen = [];
const seenSet = new Set(store.seen);

const now = Date.now();
const enriched = [];
const newHashes = [];

for (const item of items) {
  const raw = item.json || {};
  const article = normalizeArticle(raw, raw.feedUrl || '');
  if (!article.link) continue;

  const topicsMatched = matchTopics(article, cfg.topics);
  if (topicsMatched.length === 0) continue;

  const hash = hashLink(article.link);
  if (seenSet.has(hash)) continue;
  seenSet.add(hash);
  newHashes.push(hash);

  const relevance = scoreRelevance(article, topicsMatched, cfg.scoring, cfg.topics, now);
  const sentiment = scoreSentiment(article, cfg.lexicon);
  const entitiesFound = tagEntities(article, cfg.entities);

  enriched.push({
    title: article.title,
    link: article.link,
    source: article.source,
    publishedAt: article.publishedAt,
    summary: article.summary,
    topics: topicsMatched.join(', '),
    topicsList: topicsMatched,
    entities: entitiesFound.join(', '),
    entitiesList: entitiesFound,
    relevance,
    sentiment: sentiment.label,
    sentimentScore: sentiment.score,
    hash,
    scannedAt: new Date(now).toISOString()
  });
}

// Persist seen-list, trimmed FIFO.
store.seen = [...store.seen, ...newHashes].slice(-1 * (cfg.seenCap || 5000));

enriched.sort((a, b) => b.relevance - a.relevance);
return enriched.map(a => ({ json: a }));

// Build Digest — aggregate all input items into ONE HTML email item.
const cfg = $('Config').first().json;
const digestCfg = cfg.digest || {};
const minRel = digestCfg.minRelevance ?? 0;
const maxItems = digestCfg.maxItems ?? 50;

function escapeHtml(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

function badge(label, color) {
  return `<span style="display:inline-block;padding:2px 8px;border-radius:10px;background:${color};color:#fff;font-size:11px;font-weight:600;margin-right:6px;">${escapeHtml(label)}</span>`;
}

const all = items
  .map(i => i.json)
  .filter(a => (a.relevance ?? 0) >= minRel)
  .slice(0, maxItems);

const byTopic = {};
for (const a of all) {
  for (const t of (a.topicsList || [])) {
    (byTopic[t] = byTopic[t] || []).push(a);
  }
}
const topicNames = Object.keys(byTopic).sort();

const dateStr = new Date().toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' });
const total = all.length;
const subject = `${digestCfg.subjectPrefix || '[MediaMonitor]'} ${total} match${total === 1 ? '' : 'es'} — ${dateStr}`;

function sentimentColor(s) {
  if (s === 'positive') return '#137333';
  if (s === 'negative') return '#b3261e';
  return '#5f6368';
}
function relevanceColor(r) {
  if (r >= 70) return '#0b8043';
  if (r >= 40) return '#ef6c00';
  return '#9aa0a6';
}

let body = `
<div style="font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;color:#202124;max-width:760px;margin:0 auto;">
  <h1 style="font-size:22px;margin:0 0 4px 0;">Media Monitor digest</h1>
  <div style="color:#5f6368;font-size:13px;margin-bottom:24px;">
    ${dateStr} &middot; ${total} new match${total === 1 ? '' : 'es'}
    ${topicNames.length ? '&middot; topics: ' + topicNames.map(escapeHtml).join(', ') : ''}
  </div>
`;

if (total === 0) {
  body += '<p style="color:#5f6368;">No new matches in this run.</p>';
} else {
  for (const topic of topicNames) {
    const articles = byTopic[topic].slice().sort((a, b) => b.relevance - a.relevance);
    body += `<h2 style="font-size:16px;margin:24px 0 8px 0;border-bottom:1px solid #dadce0;padding-bottom:4px;">${escapeHtml(topic)} <span style="color:#5f6368;font-weight:400;font-size:13px;">(${articles.length})</span></h2>`;
    body += '<ul style="list-style:none;padding:0;margin:0;">';
    for (const a of articles) {
      const published = a.publishedAt ? new Date(a.publishedAt).toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' }) : '';
      const ents = (a.entitiesList || []).map(e => badge(e, '#1a73e8')).join('');
      body += `
        <li style="margin:0 0 14px 0;padding:10px 12px;border:1px solid #e8eaed;border-radius:8px;">
          <div style="margin-bottom:4px;">
            ${badge(a.relevance + '%', relevanceColor(a.relevance))}
            ${badge(a.sentiment, sentimentColor(a.sentiment))}
            <span style="color:#5f6368;font-size:12px;">${escapeHtml(a.source)} &middot; ${escapeHtml(published)}</span>
          </div>
          <div style="font-size:15px;font-weight:600;margin-bottom:4px;">
            <a href="${escapeHtml(a.link)}" style="color:#1a73e8;text-decoration:none;">${escapeHtml(a.title)}</a>
          </div>
          <div style="color:#3c4043;font-size:13px;line-height:1.4;margin-bottom:6px;">
            ${escapeHtml((a.summary || '').slice(0, 280))}${(a.summary || '').length > 280 ? '&hellip;' : ''}
          </div>
          ${ents ? '<div>' + ents + '</div>' : ''}
        </li>`;
    }
    body += '</ul>';
  }
}

body += `
  <hr style="border:none;border-top:1px solid #dadce0;margin:28px 0 8px 0;">
  <div style="color:#9aa0a6;font-size:11px;">media-monitor &middot; rule-based, no LLM &middot; self-hosted n8n</div>
</div>`;

return [{
  json: {
    to: digestCfg.to,
    from: digestCfg.from,
    subject,
    html: body
  }
}];
